INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Une photo de famille prise dans un jardin ensoleillé, montrant un père, une mère et deux enfants souriants autour d''une table de pique-nique avec des assiettes et des verres remplis de nourriture.', 'Portrait Familial', '["Le père a six doigts à la main droite.","Les ombres des personnes ne correspondent pas à la direction du soleil."]', 'Cette image semble normale au premier abord, mais les anomalies comme les doigts supplémentaires et les ombres incohérentes sont des signes typiques d''une génération par IA qui a du mal à reproduire l''anatomie humaine et les lois de la physique.', 10),
('Une vue panoramique d''une ville moderne avec des gratte-ciels, des voitures circulant dans les rues et des piétons marchant sur les trottoirs, sous un ciel bleu clair.', 'Paysage Urbain', '["Un bâtiment a des fenêtres qui se chevauchent de manière impossible.","Une voiture flotte légèrement au-dessus de la route."]', 'L''IA peut créer des scènes urbaines convaincantes, mais des erreurs comme des structures architecturales impossibles ou des objets en lévitation révèlent son incapacité à maintenir la cohérence spatiale.', 10),
('Chat et pelote', 'Chat étrange', '["Le chat a trois yeux.","La balle de laine a des motifs qui se répètent de façon symétrique parfaite."]', 'Bien que l''image paraisse mignonne, les anomalies comme les yeux supplémentaires et les motifs trop parfaits indiquent une génération par IA qui ne respecte pas la biologie animale ou les lois de la nature.', 10),
('Repas en famille', 'Dîner familial', '["La mère a une main avec seulement trois doigts.","Les reflets dans les verres ne correspondent pas aux objets autour."]', 'Les repas familiaux sont courants, mais les doigts manquants et les reflets incorrects sont des erreurs fréquentes de l''IA lors de la génération d''images réalistes.', 10),
('Une plage de sable fin avec des palmiers, des vagues s''écrasant doucement et des personnes se relaxant sous des parasols colorés.', 'Plage Tropicale', '["Un palmier a des feuilles qui poussent vers le bas au lieu de vers le haut.","Les ombres des parasols sont orientées dans des directions opposées."]', 'Les scènes tropicales sont attrayantes, mais l''IA peut inverser des éléments naturels comme la croissance des plantes ou créer des incohérences dans les ombres.', 10),
('Bibliothèque', 'Salle de lecture', '["Un livre ouvert a du texte qui se répète indéfiniment.","Les ombres des lampes ne touchent pas le sol."]', 'Les bibliothèques semblent intellectuelles, mais des textes répétitifs et des ombres flottantes trahissent l''origine artificielle de l''image.', 10),
('Un groupe de musiciens jouant sur une scène en extérieur, avec un public assis sur l''herbe et des lumières colorées.', 'Concert en Plein Air', '["Un musicien a un instrument avec des cordes qui se croisent de façon impossible.","Le public a des visages identiques."]', 'Les concerts sont dynamiques, mais l''IA peut créer des instruments déformés et des visages clonés, révélant son manque de créativité originale.', 10),
('Cuisine moderne', 'Cuisine inversée', '["Un robinet a de l''eau qui coule vers le haut.","Les poignées des tiroirs sont asymétriques."]', 'Les cuisines modernes paraissent fonctionnelles, mais des éléments physiques impossibles comme l''eau inversée montrent les limites de l''IA.', 10),
('Jardin fleuri', 'Nature géométrique', '["Un arbre a des branches qui forment des cercles parfaits.","Les fleurs ont des pétales qui se répètent exactement."]', 'La nature semble magique, mais les formes géométriques parfaites et les répétitions indiquent une génération par IA sans variation naturelle.', 10),
('Match de sport', 'Stade incohérent', '["Un joueur a des jambes disproportionnées.","Les banderoles ont du texte illisible."]', 'Les événements sportifs sont excitants, mais les proportions corporelles étranges et le texte brouillé sont des signes d''IA.', 10),
('Rue européenne', 'Mobilier impossible', '["Une chaise a cinq pieds.","Les reflets dans les vitres montrent des objets inexistants."]', 'Les scènes urbaines européennes semblent authentiques, mais des meubles déformés et des reflets erronés trahissent l''IA.', 10),
('Laboratoire', 'Matériel déformé', '["Un microscope a des lentilles qui se chevauchent.","Les visages des scientifiques sont flous."]', 'Les labos paraissent sérieux, mais les équipements impossibles et les visages indistincts indiquent une génération imparfaite.', 10),
('Station de ski', 'Sports d''hiver', '["Un skieur a des skis qui se courbent vers l''arrière.","Les ombres des montagnes sont absentes."]', 'Les paysages hivernaux sont pittoresques, mais des équipements déformés et des ombres manquantes révèlent l''IA.', 10),
('Parc', 'Fontaine impossible', '["Une plante a des feuilles en forme de carrés parfaits.","L''eau de la fontaine coule vers le haut."]', 'Les jardins sont relaxants, mais les formes géométriques et les lois physiques ignorées montrent l''origine artificielle.', 10),
('Marché aux fruits', 'Fruits irréalistes', '["Un fruit a une forme impossible avec des côtés droits.","Les visages des vendeurs sont identiques."]', 'Les marchés semblent vivants, mais les formes irréalistes et les clones trahissent la génération par IA.', 10),
('Océan', 'Faune incohérente', '["Un poisson a des nageoires asymétriques.","Les coraux ont des couleurs qui se répètent en motifs."]', 'L''océan est fascinant, mais les anomalies anatomiques et les répétitions indiquent une IA incapable de diversité.', 10),
('Un open space avec des ordinateurs, des plantes d''intérieur et des employés travaillant.', 'Bureau d''Entreprise', '["Un écran d''ordinateur affiche du texte brouillé.","Les plantes ont des feuilles trop symétriques."]', 'Les bureaux modernes paraissent ordinaires, mais le texte illisible et les formes parfaites révèlent l''IA.', 10),
('Une pièce décorée avec des ballons, un gâteau et des enfants souriants autour.', 'Fête d''Anniversaire', '["Un ballon flotte sans ficelle.","Les sourires des enfants sont identiques."]', 'Les fêtes sont joyeuses, mais les objets en lévitation et les expressions clonées montrent les limites de l''IA.', 10),
('Désert', 'Cactus étrange', '["Le cactus a des épines qui pointent vers l''intérieur.","Les dunes ont des formes géométriques."]', 'Les déserts semblent vastes, mais les plantes déformées et les formes artificielles indiquent une génération IA.', 10),
('Zoo', 'Animaux disproportionnés', '["Une girafe a un cou trop court.","Les lions ont des rayures asymétriques."]', 'Les zoos sont éducatifs, mais les proportions animales incorrectes trahissent l''IA.', 10),
('Pont historique', 'Architecture impossible', '["Le pont a des arches qui se chevauchent.","Les voitures ont des roues carrées."]', 'Les sites historiques semblent authentiques, mais les structures impossibles révèlent l''origine artificielle.', 10),
('Cuisine', 'Objet en lévitation', '["Un couteau flotte dans l''air.","Les ingrédients ont des couleurs trop vives."]', 'Les cuisines paraissent accueillantes, mais les objets en suspension et les couleurs exagérées indiquent une IA.', 10),
('Un aéroport animé avec des avions décollant, des passagers attendant et des écrans d''information.', 'Aéroport International', '["Un avion a des ailes qui se croisent.","Les écrans affichent du texte brouillé."]', 'Les aéroports sont complexes, mais les avions déformés et le texte illisible indiquent une IA.', 10),
('Supermarché', 'Courses incohérentes', '["Un chariot a des roues asymétriques.","Les produits ont des étiquettes identiques."]', 'Les courses semblent normales, mais les chariots impossibles et les répétitions trahissent l''IA.', 10),
('Parc avec des manèges, des familles et des lumières colorées.', 'Parc d''Attractions', '["Un manège tourne à l''envers.","Les visages des visiteurs sont flous."]', 'Les parcs sont fun, mais les mouvements impossibles et les visages indistincts révèlent l''IA.', 10),
('Musée avec des tableaux célèbres, des sculptures et des visiteurs admirant.', 'Musée d''Art', '["Une sculpture a des parties qui se chevauchent.","Les tableaux ont des couleurs qui se fondent."]', 'L''art est subjectif, mais les formes impossibles et les couleurs erronées indiquent une génération IA.', 10),
('Gare routière', 'Bus étrange', '["Un bus a des fenêtres carrées.","Les horaires sont illisibles."]', 'Les gares sont pratiques, mais les véhicules déformés et le texte brouillé montrent les limites.', 10),
('Une piscine avec des nageurs, des gradins et de l''eau bleue.', 'Piscine Olympique', '["Un nageur a des bras trop longs.","L''eau a des vagues impossibles."]', 'Les sports aquatiques sont dynamiques, mais les proportions et les physiques erronés trahissent l''IA.', 10),
('Site antique', 'Colonnes courbées', '["Les colonnes sont courbées.","La scène a des marches asymétriques."]', 'Les sites historiques semblent anciens, mais les structures déformées indiquent une IA.', 10),
('Ferme', 'Détails impossibles', '["Une vache a des cornes en spirale.","Les champs ont des formes géométriques."]', 'Les fermes sont rurales, mais les animaux impossibles et les formes parfaits révèlent l''IA.', 10),
('Centre commercial', 'Fontaine incohérente', '["Une fontaine a de l''eau qui coule horizontalement.","Les vitrines ont des reflets erronés."]', 'Les centres commerciaux sont modernes, mais les éléments physiques impossibles trahissent l''IA.', 10),
('Château', 'Pont-levis flottant', '["Les tours ont des fenêtres ovales.","Le pont-levis flotte."]', 'Les châteaux sont majestueux, mais les architectures impossibles indiquent une génération IA.', 10),
('Plage', 'Surf impossible', '["Un surfeur a une planche courbée.","Les vagues sont statiques."]', 'Le surf est excitant, mais les équipements et les mouvements erronés révèlent l''IA.', 10),
('École', 'Matériel incohérent', '["Un ordinateur a un écran brisé.","Les livres ont des couvertures identiques."]', 'L''éducation est importante, mais les équipements défectueux et les répétitions trahissent l''IA.', 10),
('Cirque', 'Motifs répétitifs', '["Un lion a des rayures droites.","Les tentes ont des couleurs qui se répètent."]', 'Les cirques sont magiques, mais les animaux et les motifs parfaits indiquent une IA.', 10),
('Volcan', 'Physique inversée', '["La lave coule vers le haut.","Les roches ont des formes carrées."]', 'La nature est puissante, mais les lois physiques ignorées révèlent l''IA.', 10),
('Tennis', 'Objets en lévitation', '["La raquette a des cordes asymétriques.","Les balles flottent."]', 'Le tennis est précis, mais les objets en lévitation et les déformations montrent les limites.', 10),
('Aquarium', 'Eau incohérente', '["Un poisson a des écailles carrées.","L''eau a des bulles statiques."]', 'Les aquariums sont fascinants, mais les formes impossibles et les animations erronées trahissent l''IA.', 10),
('Marché', 'Objet flottant', '["Un objet flotte sans support.","Les vendeurs ont des visages identiques."]', 'Les marchés sont variés, mais les objets en suspension et les clones indiquent une IA.', 10),
('Jungle', 'Proportions étranges', '["Un singe a des bras trop courts.","Les lianes forment des cercles."]', 'La jungle est mystérieuse, mais les proportions et les formes géométriques révèlent l''IA.', 10),
('Hôtel', 'Piscine débordante', '["La piscine a de l''eau qui déborde.","Les fenêtres ont des reflets impossibles."]', 'Les hôtels sont confortables, mais les éléments physiques erronés trahissent l''IA.', 10),
('Gare', 'Train déformé', '["Un train a des roues ovales.","Les horaires sont brouillés."]', 'Les gares sont essentielles, mais les véhicules et le texte déformés indiquent une génération IA.', 10);
